@rendermode InteractiveServer
@using sv_3acd7bff77394932a78505276fb5e162.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* Step Indicator Bar *@
    <nav class="mb-4">
        <ol class="d-flex list-unstyled justify-content-between p-0 m-0 position-relative step-indicator">
            @for (int i = 0; i < StepLabels.Length; i++)
            {
                var stepIndex = i;
                var isCurrent = stepIndex == CurrentStep;
                var isCompleted = stepIndex < CurrentStep;
                var isFuture = stepIndex > CurrentStep;

                <li class="text-center flex-fill position-relative step-item @(isCurrent ? "step-current" : "") @(isCompleted ? "step-completed" : "") @(isFuture ? "step-future" : "")">
                    @if (isCompleted && !Submitted)
                    {
                        <button type="button" class="btn p-0 border-0 d-block mx-auto" @onclick="() => GoToStep(stepIndex)">
                            <span class="step-circle bg-success text-white">✓</span>
                            <div class="small mt-1 text-success fw-semibold">@StepLabels[stepIndex]</div>
                        </button>
                    }
                    else
                    {
                        <div>
                            <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@(stepIndex + 1)</span>
                            <div class="small mt-1 @(isCurrent ? "text-primary fw-semibold" : "text-muted")">@StepLabels[stepIndex]</div>
                        </div>
                    }
                </li>
            }
        </ol>
    </nav>

    <hr />

    @if (Submitted)
    {
        <div class="text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">✓</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@ApplicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        @* Validation/Error Messages *@
        @if (ErrorMessages.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var msg in ErrorMessages)
                    {
                        <li>@msg</li>
                    }
                </ul>
            </div>
        }

        @switch (CurrentStep)
        {
            case 0:
                <StepPersonalInfo FullName="@FullName" EmailAddress="@EmailAddress" Phone="@Phone" Address="@Address"
                                  FullNameChanged="v => FullName = v"
                                  EmailAddressChanged="v => EmailAddress = v"
                                  PhoneChanged="v => Phone = v"
                                  AddressChanged="v => Address = v" />
                break;
            case 1:
                <StepWorkHistory Entries="@WorkEntries" />
                break;
            case 2:
                <StepReferences References="@References" />
                break;
            case 3:
                <StepCoverLetter @bind-CoverLetterText="CoverLetterText" MaxLength="2000" />
                break;
            case 4:
                <StepReview FullName="@FullName" EmailAddress="@EmailAddress" Phone="@Phone" Address="@Address"
                            WorkEntries="@WorkEntries" References="@References" CoverLetterText="@CoverLetterText"
                            OnEditSection="GoToStep" />
                break;
        }

        @* Navigation Buttons *@
        <div class="d-flex justify-content-between mt-4">
            <div>
                @if (CurrentStep > 0)
                {
                    <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@IsProcessing">
                        ← Back
                    </button>
                }
            </div>
            <div>
                @if (CurrentStep < StepLabels.Length - 1)
                {
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@IsProcessing">
                        @if (IsProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Next →
                    </button>
                }
                else
                {
                    <button class="btn btn-success" @onclick="SubmitApplication" disabled="@IsProcessing">
                        @if (IsProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Submit Application
                    </button>
                }
            </div>
        </div>
    }
</div>

<style>
    .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        border-radius: 50%;
        font-weight: bold;
        font-size: 0.9rem;
    }
    .step-completed button:hover .step-circle {
        box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
    }
</style>

