    {
        switch (CurrentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(FullName)) ErrorMessages.Add("Full name is required.");
                if (string.IsNullOrWhiteSpace(EmailAddress)) ErrorMessages.Add("Email is required.");
                if (string.IsNullOrWhiteSpace(Phone)) ErrorMessages.Add("Phone is required.");
                if (string.IsNullOrWhiteSpace(Address)) ErrorMessages.Add("Address is required.");
                break;
            case 1:
                for (int i = 0; i < WorkEntries.Count; i++)
                {
                    var e = WorkEntries[i];
                    var pos = i + 1;
                    if (string.IsNullOrWhiteSpace(e.Company)) ErrorMessages.Add($"Position {pos}: Company is required.");
                    if (string.IsNullOrWhiteSpace(e.Title)) ErrorMessages.Add($"Position {pos}: Job title is required.");
                    if (e.StartDate == default) ErrorMessages.Add($"Position {pos}: Start date is required.");
                    if (!e.IsCurrent && e.EndDate == default) ErrorMessages.Add($"Position {pos}: End date is required (or mark as current).");
                }
                break;
            case 2:
                if (References.Count < 2) ErrorMessages.Add("At least 2 references are required.");
                for (int i = 0; i < References.Count; i++)
                {
                    var r = References[i];
                    var num = i + 1;
                    if (string.IsNullOrWhiteSpace(r.Name)) ErrorMessages.Add($"Reference {num}: Name is required.");
                    if (string.IsNullOrWhiteSpace(r.Relationship)) ErrorMessages.Add($"Reference {num}: Relationship is required.");
                    if (string.IsNullOrWhiteSpace(r.Email)) ErrorMessages.Add($"Reference {num}: Email is required.");
                    if (string.IsNullOrWhiteSpace(r.Phone)) ErrorMessages.Add($"Reference {num}: Phone is required.");
                }
                break;
            case 3:
                if (string.IsNullOrWhiteSpace(CoverLetterText)) ErrorMessages.Add("Cover letter is required.");
                break;
        }
        return ErrorMessages.Count == 0;
    }

    private async Task SubmitApplication()
    {
        ErrorMessages.Clear();
        IsProcessing = true;

        try
        {
            var personal = new PersonalInfo(FullName, EmailAddress, Phone, Address);
            var workHistory = new WorkHistory(WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : (e.EndDate == default ? null : e.EndDate), e.Description)
            ).ToList());
            var refs = References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(personal, workHistory, refs, CoverLetterText);
            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            Submitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessages.Add($"Submission failed: {ex.Message}");
        }
        finally
        {
            IsProcessing = false;
        }
    }

    // Mutable models for form binding
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

