toolArgs.file_text:
@using static sv_3acd7bff77394932a78505276fb5e162.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Title" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date @(entry.IsCurrent ? "" : "*")</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input type="checkbox" class="form-check-input" id="current-@index" @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
                <div class="col-12">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="3" @bind="entry.Description"></textarea>
                </div>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary" @onclick="AddEntry">
    + Add Another Position
</button>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }
}

@using static sv_3acd7bff77394932a78505276fb5e162.Components.Pages.Apply

<h4 class="mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Relationship" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="reference.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary" @onclick="AddReference">
        + Add Reference
    </button>
}

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

